import{_ as a,o as t,c as r,a0 as o}from"./chunks/framework.B_R3rS_4.js";const m=JSON.parse('{"title":"Architecture & Quadtree System","description":"","frontmatter":{},"headers":[],"relativePath":"technical/architecture.md","filePath":"technical/architecture.md"}'),i={name:"technical/architecture.md"};function s(n,e,d,c,l,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="architecture-quadtree-system" tabindex="-1">Architecture &amp; Quadtree System <a class="header-anchor" href="#architecture-quadtree-system" aria-label="Permalink to &quot;Architecture &amp; Quadtree System&quot;">​</a></h1><p>The <code>modernRtiViewer</code> is built as a highly performant combination of Vue 3 for UI components and state management, and Three.js for raw WebGL rendering.</p><h2 id="vue-3-three-js-integration" tabindex="-1">Vue 3 &amp; Three.js Integration <a class="header-anchor" href="#vue-3-three-js-integration" aria-label="Permalink to &quot;Vue 3 &amp; Three.js Integration&quot;">​</a></h2><p>Unlike traditional 3D applications where the render loop constantly draws frames (even when nothing changes), this viewer uses a <strong>reactive render pipeline</strong>.</p><p>In <code>RtiViewer.vue</code>, Vue&#39;s reactive references (like <code>camera.value.zoom</code> or <code>lightDir.value</code>) trigger Three.js renders <em>only</em> when necessary (e.g. during an active pan/zoom interaction, or when new tiles finish loading). This drastically reduces CPU/GPU usage when the user is idle.</p><h2 id="the-quadtree-manager-lod-system" tabindex="-1">The Quadtree Manager (LOD System) <a class="header-anchor" href="#the-quadtree-manager-lod-system" aria-label="Permalink to &quot;The Quadtree Manager (LOD System)&quot;">​</a></h2><p>RTI images are often extremely large (e.g. 16,384 x 16,384 pixels or more). Loading such an image directly into the browser&#39;s memory is impossible. To solve this, the original RTI format chunks the image into smaller 256x256 pixel tiles across multiple &quot;zoom levels&quot;.</p><p>The <code>QuadtreeManager.js</code> component is responsible for orchestrating this hierarchy.</p><h3 id="how-it-works" tabindex="-1">How it works: <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works:&quot;">​</a></h3><ol><li><strong>Tree Construction:</strong> When <code>info.xml</code> is parsed, the Quadtree calculates how many zoom levels exist (e.g. from Level 0 with a single tile, up to Level N).</li><li><strong>Intersection Testing:</strong> As the user moves the camera, <code>updateTiles()</code> calculates the visible &quot;World Box&quot; of the camera in normalized space <code>[0, 1]</code>. The Quadtree recursively traverses its nodes, checking if a node&#39;s bounding box intersects with the camera&#39;s view.</li><li><strong>LOD Selection:</strong> The manager checks the camera&#39;s zoom level. The target <code>projectedTileSize</code> dictates the desired Level of Detail (LOD). If a deeper level is needed, it fetches the 4 children of the current node.</li><li><strong>Tile Loading:</strong> The selected tile IDs are then loaded asynchronously. If a high-res tile isn&#39;t loaded yet, the system temporarily keeps the lower-resolution parent tile visible as a fallback to prevent &quot;popping&quot; or empty gaps.</li></ol><h3 id="padding-and-bounds-masking" tabindex="-1">Padding and Bounds Masking <a class="header-anchor" href="#padding-and-bounds-masking" aria-label="Permalink to &quot;Padding and Bounds Masking&quot;">​</a></h3><p>RTI images are padded to the nearest power of 2 (e.g. a 4096px image is padded to an 8192px grid). The <code>QuadtreeManager</code> calculates an <code>imgBox</code> which restricts rendering exclusively to the valid data boundaries. This boundary is passed to the shaders as <code>uBounds</code> to force all padded (black) areas to remain pure black, preventing random shader artifacts at the edges of the image.</p>',12)])])}const g=a(i,[["render",s]]);export{m as __pageData,g as default};
